import{_ as d,C as u,o as r,c as h,a2 as o,b as l,w as a,a as i,E as s,a3 as n,j as c}from"./chunks/framework.Bj6f68Cg.js";const k=JSON.parse('{"title":"Aperture-MCP","description":"","frontmatter":{},"headers":[],"relativePath":"projects/aperture-mcp.md","filePath":"projects/aperture-mcp.md"}'),p={name:"projects/aperture-mcp.md"};function P(y,e,m,C,g,_){const t=u("Mermaid");return r(),h("div",null,[e[2]||(e[2]=o('<h1 id="aperture-mcp" tabindex="-1">Aperture-MCP <a class="header-anchor" href="#aperture-mcp" aria-label="Permalink to &quot;Aperture-MCP&quot;">​</a></h1><p>MCP Client와 Target MCP Server 사이에서 <code>tools/call</code>을 정책으로 통제하는 Rust 기반 Zero-trust Policy Proxy MVP입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>MVP</code></li><li><strong>저장소 주소</strong>: <a href="https://github.com/devcy0922/aperture-mcp" target="_blank" rel="noreferrer">GitHub (devcy0922/aperture-mcp)</a></li><li><strong>라이선스</strong>: MIT</li><li><strong>주요 언어</strong>: Rust</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>MCP Client가 Target Server의 Tool을 직접 호출하면 실제 실행 직전에 조직 정책이나 사용자 승인 필요 여부를 일관되게 판단할 경계가 없습니다. 각 MCP Server에 정책 코드를 중복 구현하면 Enforcement 결과와 오류 형식도 달라집니다.</p><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>기존 MCP Server를 수정하지 않고 앞단 Wrapper가 JSON-RPC Stream을 중계하면서 <code>tools/call</code>만 Policy Gateway에 질의하고, 고위험 요청을 Child Process에 전달하기 전에 차단하는 구조를 검증하기 위해 만들었습니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li>Target MCP Server를 Child Process로 실행</li><li>stdin/stdout JSON-RPC Line 중계</li><li><code>tools/call</code> Method와 Tool Name 식별</li><li>Policy Gateway <code>/decide</code> 연동</li><li><code>approval_required</code> 요청의 선택적 차단</li><li>차단 시 JSON-RPC Error Payload 반환</li><li>Child Process 종료와 Stream 정리</li></ul><hr><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',13)),(r(),l(n,null,{default:a(()=>[s(t,{id:"mermaid-88",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Client%5B%22MCP%20Client%22%5D%20--%3E%20Proxy%5B%22Aperture-MCP%20Proxy%22%5D%0A%20%20%20%20Proxy%20--%3E%7C%22tools%2Fcall%20risk%20query%22%7C%20Policy%5B%22Policy%20Gateway%20%2Fdecide%22%5D%0A%20%20%20%20Proxy%20--%3E%7C%22allowed%20JSON-RPC%22%7C%20Server%5B%22Target%20MCP%20Server%22%5D%0A%20%20%20%20Server%20--%3E%20Proxy%0A%20%20%20%20Proxy%20--%3E%20Client%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=c("h2",{id:"_5-request-flow",tabindex:"-1"},[i("5. Request Flow "),c("a",{class:"header-anchor",href:"#_5-request-flow","aria-label":'Permalink to "5. Request Flow"'},"​")],-1)),(r(),l(n,null,{default:a(()=>[s(t,{id:"mermaid-92",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Client%20as%20MCP%20Client%0A%20%20%20%20participant%20Proxy%20as%20Aperture-MCP%0A%20%20%20%20participant%20Policy%20as%20Policy%20Gateway%0A%20%20%20%20participant%20Server%20as%20Target%20MCP%20Server%0A%20%20%20%20Client-%3E%3EProxy%3A%20JSON-RPC%20tools%2Fcall%0A%20%20%20%20Proxy-%3E%3EPolicy%3A%20decide(tool_name%2C%20arguments)%0A%20%20%20%20alt%20approval_required%20and%20block%20enabled%0A%20%20%20%20%20%20%20%20Policy--%3E%3EProxy%3A%20high%20risk%0A%20%20%20%20%20%20%20%20Proxy--%3E%3EClient%3A%20JSON-RPC%20error%20-32603%0A%20%20%20%20else%20allowed%0A%20%20%20%20%20%20%20%20Policy--%3E%3EProxy%3A%20allow%0A%20%20%20%20%20%20%20%20Proxy-%3E%3EServer%3A%20original%20JSON-RPC%20request%0A%20%20%20%20%20%20%20%20Server--%3E%3EProxy%3A%20JSON-RPC%20response%0A%20%20%20%20%20%20%20%20Proxy--%3E%3EClient%3A%20response%20relay%0A%20%20%20%20end%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[i(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=o('<h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><ul><li><strong>Wrapper 방식</strong>: Target MCP Server의 구현을 변경하지 않고 실행 명령 앞에 Proxy를 배치합니다.</li><li><strong>Method 단위 최소 개입</strong>: <code>tools/call</code>만 정책 판단 대상으로 삼고 Initialize, List와 일반 응답은 그대로 중계합니다.</li><li><strong>환경 기반 Enforcement</strong>: <code>GOVAIL_ROUTER_DECIDE_URL</code>과 <code>GOVAIL_BLOCK_ON_RISK</code>로 정책 Endpoint와 차단 동작을 분리합니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><ul><li>차단이 활성화된 고위험 요청은 Target Child Process로 전달하지 않습니다.</li><li>정책 응답과 JSON-RPC Parsing 실패 시 허용 여부를 명확히 정의해야 하며 운영 적용 전 fail-closed 정책을 강화해야 합니다.</li><li>이 프로젝트는 Database Schema나 Local File을 직접 제공하는 MCP Server가 아닙니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li>Intercept한 Tool Name과 차단 여부를 stderr에 기록해 Host Logging Pipeline에서 수집할 수 있습니다.</li><li>Client에는 표준 JSON-RPC Error 형태로 차단 결과를 반환합니다.</li><li>공개 MVP는 중앙 Metric Backend보다 Policy Decision과 Relay 동작 검증에 초점을 둡니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>Runtime</strong>: Rust, Tokio</li><li><strong>Protocol</strong>: JSON-RPC over stdin/stdout</li><li><strong>Policy Integration</strong>: HTTP <code>/decide</code></li><li><strong>Verification</strong>: Mock Policy Gateway, Mock MCP Server</li></ul><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><p>Target MCP Server 실행 명령 앞에 Proxy를 배치합니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aperture-mcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/target-mcp-server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --arg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> value</span></span></code></pre></div><p>실제 Policy Endpoint와 차단 모드는 실행 환경 변수로 주입합니다.</p><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>현재는 Line-delimited stdin/stdout Transport를 대상으로 하며 Network MCP Transport는 지원하지 않습니다.</li><li>Policy Gateway 장애와 Timeout에 대한 운영 수준의 Circuit Breaker가 없습니다.</li><li>사용자 승인 UI와 Approval Resume Flow는 범위에 포함하지 않습니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>Policy Timeout과 장애 시 fail-closed 동작 강화</li><li>Decision Audit Schema와 Prometheus Metric 추가</li><li>MCP 고위험 Tool 시나리오를 AgentSecOps E2E에 통합</li></ul>',16))])}const S=d(p,[["render",P]]);export{k as __pageData,S as default};
